  4→/**
  5→ * Batch-fetch public user profiles for a list of author IDs.
  6→ */
  7→const fetchAuthorProfiles = async (authorIds) => {
  8→    const unique = [...new Set(authorIds.filter(Boolean))];
  9→    if (unique.length === 0) return {};
 10→
 11→    const { data, error } = await supabase
 12→        .from('users')
 13→        .select('id, name, image_url, username, badge')
 14→        .in('id', unique);
 15→
 16→    if (error) {
 17→        console.error('supabase error fetching author profiles:', error.message);
 18→        return {};
 19→    }
 20→
 21→    const map = {};
 22→    (data || []).forEach(u => { map[u.id] = u; });
 23→    return map;
 24→};
