145→export const getStoryByIdService = async (storyId, userId) => {
146→    if (!storyId) {
147→        throw { status: 400, error: 'storyId is required' };
148→    }
149→
150→    const { data: story, error } = await supabase
151→        .from('stories')
152→        .select('*')
153→        .eq('id', storyId)
154→        .single();
155→
156→    if (error || !story) {
157→        console.error('supabase error fetching story:', error?.message);
158→        throw { status: 404, error: 'story not found' };
159→    }
160→
161→    // Non-author can't see private stories
162→    if (story.privacy === 'private' && story.author_id !== userId) {
163→        throw { status: 404, error: 'story not found' };
164→    }
165→
166→    // Fetch author profile + chapters in parallel
167→    const [authorMap, chapResult] = await Promise.all([
168→        fetchAuthorProfiles([story.author_id]),
169→        supabase
170→            .from('chapters')
171→            .select('id, chapter_number, title, word_count, status, published_at, created_at')
172→            .eq('story_id', storyId)
173→            .order('chapter_number', { ascending: true }),
174→    ]);
175→
176→    if (chapResult.error) {
177→        console.error('supabase error fetching chapters:', chapResult.error.message);
178→    }
179→
180→    // Filter chapters for non-authors
181→    const isAuthor = story.author_id === userId;
182→    const chapters = chapResult.data || [];
183→    const visibleChapters = isAuthor
184→        ? chapters
185→        : chapters.filter(c => c.status === 'published');
186→
187→    // Fetch user flags
188→    let hasVoted = false;
189→    let inLibrary = false;
190→    let readingProgress = null;
191→
192→    if (userId) {
193→        const [voteRes, libRes, progressRes] = await Promise.all([
194→            supabase.from('story_votes').select('id').eq('story_id', storyId).eq('user_id', userId).maybeSingle(),
195→            supabase.from('story_library').select('id').eq('story_id', storyId).eq('user_id', userId).maybeSingle(),
196→            supabase.from('reading_progress').select('chapter_id, scroll_position, last_read_at').eq('story_id', storyId).eq('user_id', userId).maybeSingle(),
197→        ]);
198→
199→        hasVoted = !!voteRes.data;
200→        inLibrary = !!libRes.data;
201→        readingProgress = progressRes.data || null;
202→    }
203→
204→    return {
205→        ...story,
206→        users: authorMap[story.author_id] || null,
207→        chapters: visibleChapters,
208→        has_voted: hasVoted,
209→        in_library: inLibrary,
210→        reading_progress: readingProgress,
211→        is_author: isAuthor,
212→    };
213→};
