 16→    createChapterController,
 17→    getChapterController,
 18→    updateChapterController,
 19→    deleteChapterController,
 20→    reorderChaptersController,
 21→} from "../controller/chapterController.js";
 22→
 23→import {
 24→    toggleVoteController,
 25→    toggleLibraryController,
 26→    getCommentsController,
 27→    getCommentCountsController,
 28→    addCommentController,
 29→    saveProgressController,
 30→    getProgressController,
 31→} from "../controller/storyInteractController.js";
 32→
 33→const storyRouter = express.Router();
 34→
 35→const upload = multer({
 36→    storage: multer.memoryStorage(),
 37→    limits: { fileSize: 10 * 1024 * 1024 },
 38→}).single('image');
 39→
 40→// ── Auth middleware (same pattern as routes.js) ──
 41→
 42→const extractBearerToken = (authHeader = "") => {
 43→    const trimmed = typeof authHeader === "string" ? authHeader.trim() : "";
 44→    if (!trimmed) return "";
 45→    const bearerMatch = trimmed.match(/^Bearer\s+(.+)$/i);
 46→    if (bearerMatch?.[1]) return bearerMatch[1].trim();
 47→    return trimmed;
 48→};
 49→
 50→const resolveAuthUser = async (token) => {
 51→    if (!token) return { user: null, error: null };
 52→    const { data: authData, error: authError } = await supabase.auth.getUser(token);
 53→    if (authError || !authData?.user?.id) {
 54→        return { user: null, error: authError || new Error("missing user id") };
 55→    }
 56→    return { user: authData.user, error: null };
 57→};
 58→
 59→const requireAuth = async (req, res, next) => {
 60→    const token = extractBearerToken(req.headers?.authorization);
 61→    if (!token) return res.status(401).json({ error: 'not authorized' });
 62→    const { user, error } = await resolveAuthUser(token);
 63→    if (error || !user?.id) return res.status(401).json({ error: 'not authorized' });
 64→    req.userId = user.id;
 65→    req.authUser = user;
 66→    return next();
 67→};
 68→
 69→const optionalAuth = async (req, _res, next) => {
 70→    const token = extractBearerToken(req.headers?.authorization);
 71→    if (!token) return next();
 72→    const { user } = await resolveAuthUser(token);
 73→    if (user?.id) {
 74→        req.userId = user.id;
 75→        req.authUser = user;
 76→    }
 77→    return next();
 78→};
 79→
 80→// ── Story routes ──
 81→storyRouter.post('/stories', requireAuth, upload, createStoryController);
 82→storyRouter.get('/stories', optionalAuth, getStoriesController);
 83→storyRouter.get('/stories/my', requireAuth, getMyStoriesController);
 84→storyRouter.get('/stories/user/:userId', optionalAuth, getUserStoriesController);
 85→storyRouter.get('/stories/:storyId', optionalAuth, getStoryByIdController);
 86→storyRouter.patch('/stories/:storyId', requireAuth, upload, updateStoryController);
 87→storyRouter.delete('/stories/:storyId', requireAuth, deleteStoryController);
